import Foundation

protocol TradeExecutionService {
    func executeTrade(symbol: String, quantity: Int, orderType: OrderType) async throws -> Trade
}

// TradeExecutionManager.swift

class TradeExecutionManager: TradeExecutionService {
    private let apiClient: APIClient

    init(apiClient: APIClient) {
        self.apiClient = apiClient
    }

    func executeTrade(symbol: String, quantity: Int, orderType: OrderType) async throws -> Trade {
        let request = TradeRequest(symbol: symbol, quantity: quantity, orderType: orderType)
        let response = try await apiClient.executeTrade(request: request)
        return response.trade
    }
}

// PortfolioManager.swift

class PortfolioManager {
    private let apiClient: APIClient

    init(apiClient: APIClient) {
        self.apiClient = apiClient
    }

    func getPortfolio() async throws -> Portfolio {
        let response = try await apiClient.getPortfolio()
        return response.portfolio
    }

    func updatePortfolio(with trades: [Trade]) async throws {
        for trade in trades {
            try await apiClient.updatePortfolio(with: trade)
        }
    }
}

